mapper.select:
SELECT d.id AS default_id, f.script_id, f.script_version_id, f.id AS field_config_id, f.step_id, f.field_scope, f.field_path, f.field_name, f.data_type, d.default_value, d.value_source, d.created_time, d.updated_time FROM field_config f LEFT JOIN script_field_default d ON d.field_config_id = f.id AND d.script_version_id = f.script_version_id AND d.deleted = 0 WHERE f.script_id = #{scriptId} AND f.script_version_id = #{versionId} AND f.deleted = 0
AND f.step_id = #{stepId}
AND f.field_scope = #{fieldScope}
ORDER BY f.step_id ASC, f.field_scope ASC, f.field_path ASC

